create or replace function public.record_qr_scan (p_qr_id uuid, p_device text default null, p_ip_hash text default null) returns void language plpgsql security definer set search_path = public as $$ begin if not exists (select 1 from public.qr_codes where id = p_qr_id) then return; end if; insert into public.scan_logs (qr_id, device, ip_hash) values (p_qr_id, nullif(trim(p_device), ''), nullif(trim(p_ip_hash), '')); update public.qr_codes set scans = scans + 1 where id = p_qr_id and status = 'active'; end; $$; grant execute on function public.record_qr_scan (uuid, text, text) to anon; grant execute on function public.record_qr_scan (uuid, text, text) to authenticated;;
